  device_type: 'vertical',
  crop: 'lettuce',
  zone: 'tier_1',
  device_id: 'SIM_VERTICAL_NODE_004'
});

// Simulation state
global.set('sim_running', false);
global.set('sim_speed', 1);

node.status({fill:'green', shape:'dot', text:'Initialized'});

msg.payload = {
  status: 'initialized',
  farms: ['bafang', 'bertoua', 'maroua', 'vertical'],
