};

return msg;

const action = msg.payload.action;
const userId = global.get('user_id');

if (action === 'start') {
    global.set('sim_running', true);
    node.status({fill:'green', shape:'dot', text:'RUNNING'});
} else {
    global.set('sim_running', false);
    node.status({fill:'red', shape:'ring', text:'STOPPED'});
}

// Publish control event
msg.topic = 'farmassist/control/events';
msg.payload = {
  event: 'simulation_control',
  action: action,
  user_id: userId,
  timestamp: Date.now(),
  running: global.get('sim_running')
};

return msg;

if (!global.get('sim_running')) {
    node.status({fill:'grey', shape:'ring', text:'Stopped'});
    return null;
}

const userId = global.get('user_id');
const farm = global.get('farm_bafang');
const hour = new Date().getHours();

// Temperature with diurnal cycle
const temp_air = +(27.5 + 6.0 * Math.sin((hour - 5) * Math.PI / 12) + (Math.random() - 0.5) * 1.2).toFixed(2);
const humidity = +(Math.max(30, Math.min(98, 78 - (temp_air - 27.5) * 2.5 + (Math.random() - 0.5) * 4))).toFixed(2);

// Moisture decreases over time, resets occasionally
let moi = context.get('moi') || 70;
moi -= 0.08;
if (Math.random() < 0.002) moi = 85;  // Rain event
moi = +Math.max(10, Math.min(95, moi)).toFixed(2);
context.set('moi', moi);

// pH drifts slowly
let ph = context.get('ph') || 6.2;
ph += (Math.random() - 0.5) * 0.02;
ph = +Math.max(4.5, Math.min(8.5, ph)).toFixed(2);
context.set('ph', ph);

// Salinity increases slowly
let sal = context.get('sal') || 1.0;
sal += 0.005;
if (Math.random() < 0.001) sal = 0.8;
sal = +Math.max(0.1, Math.min(5.0, sal)).toFixed(2);
context.set('sal', sal);

// Light based on time of day
const light_lux = +(Math.max(0, 65000 * Math.sin((hour - 6) * Math.PI / 12) + (Math.random() - 0.5) * 4000)).toFixed(0);
const solar_mw = light_lux > 1000 ? +(light_lux * 0.018).toFixed(0) : 0;

// Battery charges during day, drains at night
let batt = context.get('batt') || 95;
batt = solar_mw > 0 ? Math.min(100, batt + 0.008) : Math.max(20, batt - 0.015);
batt = +batt.toFixed(1);
context.set('batt', batt);

const seq = (context.get('seq') || 0) + 1;
context.set('seq', seq);

msg.topic = `farmassist/${userId}/${farm.farm_id}/${farm.device_id}/telemetry`;
msg.payload = {
  schema_ver: '2.0.0',
  user_id: userId,
  farm_id: farm.farm_id,
  plot_id: farm.plot_id,
  device_id: farm.device_id,
  device_type: farm.device_type,
  zone: farm.zone,
  timestamp: Date.now(),
  seq: seq,
  source: 'simulation',
  sensors: {
    temp_air: temp_air,
    humidity: humidity,
    light_lux: light_lux,
    co2_ppm: null,
    temp_soil: +(temp_air - 4.5 + (Math.random() - 0.5) * 0.8).toFixed(2),
    moisture_1: moi,
    moisture_2: +(moi - 3 + (Math.random() - 0.5) * 2).toFixed(2),
    soil_ph: ph,
    salinity: sal,
    flow_lph: null,
    water_temp: null,
    ec_solution: null,
    ph_solution: null,
    do_mgl: null,
    water_level_pct: null,
    tier: null
  },
  actuators: {
    irrigation: false,
    pump: false,
    ventilation: false,
    grow_light: false
  },
  meta: {
    firmware_ver: 'sim-2.0.0',
    battery_pct: batt,
    solar_mw: solar_mw,
    wifi_rssi: -52 - Math.floor(Math.random() * 8),
    uptime_sec: seq * 60,
    free_heap: 145000 + Math.floor(Math.random() * 10000)
  }
};

node.status({fill:'green', shape:'dot', text: `T:${temp_air}C H:${humidity}%`});
return msg;

