const humidity = +(Math.max(12, Math.min(80, 42 - (temp_air - 35) * 1.8 + (Math.random() - 0.5) * 6))).toFixed(2);

let moi = context.get('moi') || 52;
moi -= 0.15;
if (Math.random() < 0.0006) moi = 72;
moi = +Math.max(8, Math.min(90, moi)).toFixed(2);
