if (!global.get('sim_running')) {
    node.status({fill:'grey', shape:'ring', text:'Stopped'});
    return null;
}

const userId = global.get('user_id');
const farm = global.get('farm_vertical');
const hour = new Date().getHours();
const lights_on = (hour >= 6 && hour < 22);

// EC drifts down, resets with nutrient addition
let ec = context.get('ec') || 2.4;
ec -= 0.008;
if (Math.random() < 0.030) ec += 0.15;
ec = +Math.max(0.5, Math.min(4.0, ec)).toFixed(3);
context.set('ec', ec);

// pH drifts down (acidification)
let ph = context.get('ph') || 6.0;
ph -= 0.005;
if (Math.random() < 0.040) ph += 0.12;
ph = +Math.max(4.5, Math.min(8.0, ph)).toFixed(3);
context.set('ph', ph);

// Water temperature
let wt = context.get('wt') || 20.5;
wt += (Math.random() - 0.5) * 0.1 + (lights_on ? 0.005 : -0.003);
wt = +Math.max(16, Math.min(28, wt)).toFixed(2);
context.set('wt', wt);

// Dissolved oxygen (Henry's Law: decreases with temp)
const do_mgl = +(14.6 - 0.4 * (wt - 15) + (Math.random() - 0.5) * 0.3).toFixed(2);

// Water level slowly decreases
let wl = context.get('wl') || 80;
wl -= 0.05;
if (wl < 30) wl = 85;  // Refill
wl = +Math.max(10, Math.min(95, wl)).toFixed(2);
context.set('wl', wl);

// Flow rate
const flow = +(4.0 + (Math.random() - 0.5) * 0.4).toFixed(2);

// CO2 (higher during lights-off)
const co2_base = lights_on ? 450 : 650;
const co2_ppm = Math.floor(co2_base + (Math.random() - 0.5) * 100);

const seq = (context.get('seq') || 0) + 1;
context.set('seq', seq);

msg.topic = `farmassist/${userId}/${farm.farm_id}/${farm.device_id}/telemetry`;
msg.payload = {
  schema_ver: '2.0.0',
  user_id: userId,
  farm_id: farm.farm_id,
  plot_id: farm.plot_id,
  device_id: farm.device_id,
  device_type: farm.device_type,
  zone: farm.zone,
  timestamp: Date.now(),
  seq: seq,
  source: 'simulation',
  sensors: {
    temp_air: +(22.0 + (Math.random() - 0.5) * 2).toFixed(2),
    humidity: +(65 + (Math.random() - 0.5) * 8).toFixed(2),
    light_lux: lights_on ? Math.floor(38000 + Math.random() * 4000) : 0,
    co2_ppm: co2_ppm,
    temp_soil: null,
    moisture_1: null,
    moisture_2: null,
    soil_ph: null,
    salinity: null,
    flow_lph: flow,
    water_temp: wt,
    ec_solution: ec,
    ph_solution: ph,
    do_mgl: do_mgl,
    water_level_pct: wl,
    tier: 1
  },
  actuators: {
    irrigation: false,
    pump: true,
    ventilation: wt > 25,
    grow_light: lights_on
  },
  meta: {
    firmware_ver: 'sim-2.0.0',
    battery_pct: 100,
    solar_mw: 0,
    wifi_rssi: -42 - Math.floor(Math.random() * 6),
    uptime_sec: seq * 60,
    free_heap: 156000 + Math.floor(Math.random() * 8000)
  }
};

node.status({fill:'blue', shape:'dot', text: `EC:${ec} pH:${ph} DO:${do_mgl}`});
return msg;

const anomalyType = msg.payload;
const userId = global.get('user_id');

// Determine target device
let deviceId, farmId, plotId, deviceType, zone;

if (['SALINITY_CRITICAL', 'PH_CRITICAL', 'MOISTURE_CRITICAL'].includes(anomalyType)) {
  const farm = global.get('farm_bafang');
  deviceId = farm.device_id;
  farmId = farm.farm_id;
  plotId = farm.plot_id;
  deviceType = 'horizontal';
  zone = farm.zone;
} else {
  const farm = global.get('farm_vertical');
  deviceId = farm.device_id;
  farmId = farm.farm_id;
  plotId = farm.plot_id;
  deviceType = 'vertical';
  zone = farm.zone;
}

// Base sensor values
const baseSensors = {
  temp_air: 28.0,
  humidity: 68.0,
  light_lux: 42000,
  co2_ppm: deviceType === 'vertical' ? 650 : null,
  temp_soil: 24.0,
  moisture_1: 58.0,
  moisture_2: 55.0,
  soil_ph: 6.5,
  salinity: 1.2,
  flow_lph: deviceType === 'vertical' ? 4.2 : null,
  water_temp: deviceType === 'vertical' ? 21.5 : null,
  ec_solution: deviceType === 'vertical' ? 2.4 : null,
  ph_solution: deviceType === 'vertical' ? 6.1 : null,
  do_mgl: deviceType === 'vertical' ? 7.2 : null,
  water_level_pct: deviceType === 'vertical' ? 68.0 : null,
  tier: deviceType === 'vertical' ? 1 : null
};

// Apply anomaly
switch(anomalyType) {
  case 'SALINITY_CRITICAL':
    baseSensors.salinity = 4.8;
    break;
  case 'PH_CRITICAL':
    baseSensors.soil_ph = 4.2;
    break;
  case 'MOISTURE_CRITICAL':
    baseSensors.moisture_1 = 12.0;
    baseSensors.moisture_2 = 10.0;
    break;
  case 'EC_LOW':
    baseSensors.ec_solution = 0.60;
    break;
  case 'DO_CRITICAL':
    baseSensors.do_mgl = 3.2;
    baseSensors.water_temp = 30.5;
    break;
  case 'RESERVOIR_CRITICAL':
    baseSensors.water_level_pct = 12.0;
    break;
}

msg.topic = `farmassist/${userId}/${farmId}/${deviceId}/telemetry`;
msg.payload = {
  schema_ver: '2.0.0',
  user_id: userId,
  farm_id: farmId,
  plot_id: plotId,
  device_id: deviceId,
  device_type: deviceType,
  zone: zone,
  timestamp: Date.now(),
  seq: Math.floor(Date.now() / 1000),
  source: 'anomaly_injection',
  sensors: baseSensors,
  actuators: {
    irrigation: false,
    pump: deviceType === 'vertical',
    ventilation: false,
    grow_light: false
  },
  meta: {
    firmware_ver: 'sim-2.0.0',
    battery_pct: 87,
    solar_mw: 1450,
    wifi_rssi: -55,
    uptime_sec: 3600,
    free_heap: 148000,
    anomaly_type: anomalyType
  }
};

node.status({fill:'red', shape:'ring', text: `INJECTED: ${anomalyType}`});

return msg;
